// box3d.js - Modelo 3D Interactivo de la Caja de Cuadriculando en Three.js

(function () {
  let scene, camera, renderer, controls;
  let boxContainer;
  let autoRotate = true;

  const COLORS = {
    matteBlack: '#181a1b',
    white: '#ffffff'
  };

  function init() {
    const container = document.getElementById('canvas-box3d');
    if (!container) return;

    // 1. Escena
    scene = new THREE.Scene();

    // 2. CÃ¡mara
    camera = new THREE.PerspectiveCamera(
      45,
      container.clientWidth / container.clientHeight,
      0.1,
      20
    );
    camera.position.set(3.8, 2.5, 3.8); // angled perspective for the box

    // 3. Renderizador
    renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(container.clientWidth, container.clientHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.physicallyCorrectLights = true;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.15;
    container.appendChild(renderer.domElement);

    // 4. Controles
    controls = new THREE.OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.maxPolarAngle = Math.PI / 2 - 0.05;
    controls.minDistance = 1.5;
    controls.maxDistance = 7.0;
    controls.enabled = false; // Disabled by default in the gallery

    // 5. Luces
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.55);
    scene.add(ambientLight);

    const dirLight1 = new THREE.DirectionalLight(0xffffff, 0.95);
    dirLight1.position.set(5, 7, 4);
    dirLight1.castShadow = true;
    dirLight1.shadow.mapSize.width = 1024;
    dirLight1.shadow.mapSize.height = 1024;
    dirLight1.shadow.bias = -0.0003;
    scene.add(dirLight1);

    const dirLight2 = new THREE.DirectionalLight(0xffffff, 0.25);
    dirLight2.position.set(-5, 4, -4);
    scene.add(dirLight2);

    // 6. Grupo principal
    boxContainer = new THREE.Group();
    boxContainer.position.set(0, -0.3, 0);
    scene.add(boxContainer);

    // 7. Construir la Caja
    buildBox();

    // 8. UI
    setupUI();

    // 9. AnimaciÃ³n
    animate();

    // 10. Resize
    window.addEventListener('resize', onWindowResize, false);
  }

  function buildBox() {
    // Cargar la textura de la caja (la tapa)
    const textureLoader = new THREE.TextureLoader();
    const topTexture = textureLoader.load('data:image/png;base64,' + '', () => {
      // Force render once loaded
      renderer.render(scene, camera);
    });
    topTexture.wrapS = topTexture.wrapT = THREE.ClampToEdgeWrapping;
    topTexture.anisotropy = 4;

    // Materiales para la tapa (6 materiales para las 6 caras del cubo)
    const sideMaterial = new THREE.MeshStandardMaterial({
      color: new THREE.Color(COLORS.matteBlack),
      roughness: 0.85,
      metalness: 0.08
    });

    const topMaterial = new THREE.MeshStandardMaterial({
      map: topTexture,
      roughness: 0.55,
      metalness: 0.1
    });

    // En BoxGeometry, el orden de las caras es: +X, -X, +Y, -Y, +Z, -Z
    const lidMaterials = [
      sideMaterial, // +X (derecha)
      sideMaterial, // -X (izquierda)
      topMaterial,  // +Y (tapa)
      sideMaterial, // -Y (abajo)
      sideMaterial, // +Z (frente)
      sideMaterial  // -Z (atrÃ¡s)
    ];

    // Dimensiones de la caja
    const baseW = 4.0;
    const baseH = 0.8;
    const baseD = 4.0;

    const lidW = 4.04;
    const lidH = 0.81;
    const lidD = 4.04;

    // 1. Base de la caja
    const baseGeo = new THREE.BoxGeometry(baseW, baseH, baseD);
    const baseMesh = new THREE.Mesh(baseGeo, sideMaterial);
    baseMesh.position.y = baseH / 2 + 0.01;
    baseMesh.castShadow = true;
    baseMesh.receiveShadow = true;
    boxContainer.add(baseMesh);

    // 2. Tapa de la caja (cubre toda la caja)
    const lidGeo = new THREE.BoxGeometry(lidW, lidH, lidD);
    const lidMesh = new THREE.Mesh(lidGeo, lidMaterials);
    lidMesh.position.y = lidH / 2 + 0.015;
    lidMesh.castShadow = true;
    lidMesh.receiveShadow = true;
    boxContainer.add(lidMesh);

    // 3. Plano de sombra
    const floorGeo = new THREE.PlaneGeometry(8, 8);
    const floorMat = new THREE.ShadowMaterial({ opacity: 0.35 });
    const floorMesh = new THREE.Mesh(floorGeo, floorMat);
    floorMesh.rotation.x = -Math.PI / 2;
    floorMesh.position.y = 0;
    floorMesh.receiveShadow = true;
    boxContainer.add(floorMesh);
  }

  function setupUI() {
    const rotateBtn = document.getElementById('btn-box3d-rotate');
    const topBtn = document.getElementById('btn-box3d-top');
    const perspectiveBtn = document.getElementById('btn-box3d-persp');

    if (rotateBtn) {
      rotateBtn.addEventListener('click', () => {
        autoRotate = !autoRotate;
        rotateBtn.classList.toggle('is-active', autoRotate);
      });
    }
    if (topBtn) {
      topBtn.addEventListener('click', () => {
        autoRotate = false;
        animateCamera(0, 5.0, 0.01);
      });
    }
    if (perspectiveBtn) {
      perspectiveBtn.addEventListener('click', () => {
        autoRotate = false;
        animateCamera(3.8, 2.5, 3.8);
      });
    }
  }

  let cameraAnim = {
    active: false,
    targetX: 0,
    targetY: 0,
    targetZ: 0,
    speed: 0.08
  };

  function animateCamera(x, y, z) {
    cameraAnim.targetX = x;
    cameraAnim.targetY = y;
    cameraAnim.targetZ = z;
    cameraAnim.active = true;
  }

  function animate() {
    requestAnimationFrame(animate);

    if (autoRotate) {
      boxContainer.rotation.y += 0.0035;
    }

    if (cameraAnim.active) {
      camera.position.x += (cameraAnim.targetX - camera.position.x) * cameraAnim.speed;
      camera.position.y += (cameraAnim.targetY - camera.position.y) * cameraAnim.speed;
      camera.position.z += (cameraAnim.targetZ - camera.position.z) * cameraAnim.speed;
    }

    controls.update();
    renderer.render(scene, camera);
  }

  function onWindowResize() {
    const container = document.getElementById('canvas-box3d');
    if (!container) return;
    camera.aspect = container.clientWidth / container.clientHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(container.clientWidth, container.clientHeight);
  }

  function checkAndInit() {
    if (typeof THREE !== 'undefined' && THREE.OrbitControls) init();
    else setTimeout(checkAndInit, 50);
  }

  window.Box3D = {
    init: function () {
      checkAndInit();
    },
    setMode: function (isLarge) {
      if (isLarge) {
        if (controls) controls.enabled = true;
      } else {
        if (controls) controls.enabled = false;
        autoRotate = true;
        const rotateBtn = document.getElementById('btn-box3d-rotate');
        if (rotateBtn) {
          rotateBtn.classList.add('is-active');
        }
        if (camera) {
          camera.position.set(3.8, 2.5, 3.8);
        }
      }
    },
    resize: function () {
      onWindowResize();
    }
  };
})();

